// ---- utils/dom.js ----
const DOMUtils = {
  // Find closest LI element
  findClosestListItem(event) {
    if (event.target.tagName === "LI") {
      return event.target;
    } else if (event.target.parentElement?.tagName === "LI") {
      return event.target.parentElement;
    }
    return null;
  },

  // Spring animate favorite icon
  animateFavoriteIcon(iconElement) {
    iconElement.className = "bi bi-patch-check-fill matched spring-animation";
    setTimeout(() => {
      iconElement.classList.remove("spring-animation");
    }, 500);
  },

  // Fade out (not the "add" animation) and wait for mouseleave so the icon doesn't flip mid-hover.
  fadeOutFavoriteIcon(iconElement) {
    iconElement.classList.add("unfavoriting");

    const restore = () => {
      iconElement.className = "bi bi-patch-plus-fill";
      iconElement.title = chrome.i18n.getMessage("plusLabel");
    };

    iconElement.addEventListener("mouseleave", restore, { once: true });
  },
};

if (typeof window !== "undefined") {
  window.DOMUtils = DOMUtils;
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = DOMUtils;
}

// ---- utils/undoWindow.js ----
const UNDO_WINDOW_MS = 6000;

// Tracks a single pending "undo" payload behind a countdown, shared by
// History/Gemini's clear-then-undo button-swap behavior.
class UndoWindow {
  constructor(onExpire) {
    this._onExpire = onExpire;
    this._timer = null;
    this._pending = null;
  }

  get pending() {
    return this._pending;
  }

  start(payload) {
    clearTimeout(this._timer);
    this._pending = payload;
    this._timer = setTimeout(() => {
      this._pending = null;
      this._onExpire();
    }, UNDO_WINDOW_MS);
  }

  // Cancels the window and returns its payload (null if none was pending or it already expired).
  consume() {
    clearTimeout(this._timer);
    const pending = this._pending;
    this._pending = null;
    return pending;
  }
}

if (typeof window !== "undefined") {
  window.UndoWindow = UndoWindow;
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = UndoWindow;
}

// ---- hooks/popupState.js ----
const SUMMARY_TTL_MS = 24 * 60 * 60 * 1000;
const POPUP_TABS = new Set(["history", "favorite", "gemini"]);

function stringList(value) {
  return Array.isArray(value) ? value.filter((item) => typeof item === "string") : [];
}

function summaryItems(value) {
  if (!Array.isArray(value)) return [];
  return value
    .filter((item) => item && typeof item.name === "string")
    .map((item) => ({
      name: item.name,
      clue: typeof item.clue === "string" ? item.clue : "",
    }));
}

// Shared TTL check for hydrateSnapshot, reducer, and external callers
function isSummaryFresh(items, timestamp, now) {
  return (
    Array.isArray(items) &&
    items.length > 0 &&
    Number.isFinite(timestamp) &&
    timestamp > 0 &&
    timestamp <= now &&
    now - timestamp <= SUMMARY_TTL_MS
  );
}

function initialPopupSnapshot() {
  return {
    boot: "loading",
    activeTab: "history",
    activeTabTouched: false,
    history: { items: [], emptyReason: "initial" },
    favorite: { items: [], status: "empty", errorKey: null },
    summary: {
      phase: "empty",
      items: [],
      errorKey: null,
      estimateSeconds: null,
      requestId: null,
      originTabId: null,
      timestamp: null,
    },
    api: { status: "missing", token: 0 },
    video: { available: null, enabled: false, token: 0 },
    deleteMode: { source: null, selectedValues: [] },
    onboarding: { demoHistoryVisible: false },
  };
}

function hydrateSnapshot(current, payload = {}) {
  const now = Number.isFinite(payload.now) ? payload.now : Date.now();
  const persistedSummary = summaryItems(payload.summaryList);
  const timestamp = Number(payload.timestamp);
  const summaryIsFresh = isSummaryFresh(persistedSummary, timestamp, now);

  return {
    ...current,
    boot: "ready",
    // Preserve user tab selection
    activeTab: current.activeTabTouched
      ? current.activeTab
      : POPUP_TABS.has(payload.lastActiveTab)
        ? payload.lastActiveTab
        : "history",
    history: { items: stringList(payload.searchHistoryList), emptyReason: "initial" },
    favorite: {
      items: stringList(payload.favoriteList),
      status: stringList(payload.favoriteList).length ? "ready" : "empty",
      errorKey: null,
    },
    summary: summaryIsFresh
      ? {
          ...current.summary,
          phase: "ready",
          items: persistedSummary,
          timestamp,
        }
      : { ...initialPopupSnapshot().summary },
    api: {
      status: payload.geminiApiKey ? "verifying" : "missing",
      token: current.api.token + 1,
    },
    video: {
      ...current.video,
      enabled: Boolean(payload.videoSummaryToggle),
    },
  };
}

function reducePopupState(current, action = {}) {
  switch (action.type) {
    case "HYDRATE":
      return hydrateSnapshot(current, action.payload);
    case "SET_ACTIVE_TAB":
      return POPUP_TABS.has(action.tab) && action.tab !== current.activeTab
        ? {
            ...current,
            activeTab: action.tab,
            activeTabTouched: true,
            deleteMode: { source: null, selectedValues: [] },
          }
        : current;
    case "HISTORY_SET": {
      const items = stringList(action.items);
      return {
        ...current,
        history: {
          items,
          emptyReason: items.length
            ? "initial"
            : action.emptyReason || current.history.emptyReason || "initial",
        },
        deleteMode:
          current.deleteMode.source === "history" && items.length === 0
            ? { source: null, selectedValues: [] }
            : current.deleteMode,
      };
    }
    case "FAVORITE_SET": {
      const items = stringList(action.items);
      return {
        ...current,
        favorite: {
          items,
          status: items.length ? "ready" : "empty",
          errorKey: null,
        },
        deleteMode:
          current.deleteMode.source === "favorite" && items.length === 0
            ? { source: null, selectedValues: [] }
            : current.deleteMode,
      };
    }
    case "FAVORITE_ERROR":
      return {
        ...current,
        favorite: { ...current.favorite, status: "error", errorKey: action.errorKey },
      };
    case "SUMMARY_START":
      return {
        ...current,
        summary: {
          ...initialPopupSnapshot().summary,
          phase: "generating",
          requestId: action.requestId,
          originTabId: action.originTabId ?? null,
        },
      };
    case "SUMMARY_ESTIMATE":
      if (action.requestId !== current.summary.requestId) return current;
      return {
        ...current,
        summary: { ...current.summary, estimateSeconds: action.estimateSeconds ?? null },
      };
    case "SUMMARY_SUCCESS":
      if (action.requestId !== current.summary.requestId) return current;
      return {
        ...current,
        summary: {
          ...current.summary,
          phase: "ready",
          items: summaryItems(action.items),
          errorKey: null,
          estimateSeconds: null,
          requestId: null,
          timestamp: action.timestamp ?? Date.now(),
        },
      };
    case "SUMMARY_ERROR":
      if (action.requestId !== current.summary.requestId) return current;
      return {
        ...current,
        summary: {
          ...current.summary,
          phase: "error",
          items: [],
          errorKey: action.errorKey || "geminiErrorMsg",
          estimateSeconds: null,
          requestId: null,
        },
      };
    case "SUMMARY_CLEAR":
      return { ...current, summary: { ...initialPopupSnapshot().summary } };
    case "SUMMARY_STORAGE_SET": {
      if (current.summary.phase === "generating") return current;
      const items = summaryItems(action.items);
      const now = Number.isFinite(action.now) ? action.now : Date.now();
      const timestamp = Number(action.timestamp);
      const isFresh = isSummaryFresh(items, timestamp, now);
      return isFresh
        ? {
            ...current,
            summary: {
              ...initialPopupSnapshot().summary,
              phase: "ready",
              items,
              timestamp,
            },
          }
        : { ...current, summary: { ...initialPopupSnapshot().summary } };
    }
    case "API_VERIFY_START":
      return {
        ...current,
        api: { status: action.hasKey ? "verifying" : "missing", token: action.token },
      };
    case "API_VERIFY_RESULT":
      return action.token === current.api.token
        ? { ...current, api: { status: action.valid ? "valid" : "invalid", token: action.token } }
        : current;
    case "VIDEO_CONTEXT_REQUEST":
      return { ...current, video: { ...current.video, available: null, token: action.token } };
    case "VIDEO_CONTEXT_RESULT":
      return action.token === current.video.token
        ? { ...current, video: { ...current.video, available: Boolean(action.available) } }
        : current;
    case "VIDEO_TOGGLE":
      return { ...current, video: { ...current.video, enabled: Boolean(action.enabled) } };
    case "DELETE_ENTER":
      return action.source === "history" || action.source === "favorite"
        ? { ...current, deleteMode: { source: action.source, selectedValues: [] } }
        : current;
    case "DELETE_TOGGLE": {
      if (!current.deleteMode.source) return current;
      const selected = new Set(current.deleteMode.selectedValues);
      selected.has(action.value) ? selected.delete(action.value) : selected.add(action.value);
      return {
        ...current,
        deleteMode: { ...current.deleteMode, selectedValues: Array.from(selected) },
      };
    }
    case "DELETE_CANCEL":
      return { ...current, deleteMode: { source: null, selectedValues: [] } };
    case "ONBOARDING_DEMO_SET":
      return {
        ...current,
        onboarding: { ...current.onboarding, demoHistoryVisible: Boolean(action.visible) },
      };
    default:
      return current;
  }
}

class State {
  constructor() {
    this.snapshot = initialPopupSnapshot();
    this.listeners = new Set();

    // State not owned by tab reducer
    this.paymentStage = null;
    this.previousWidth = 0;
    this.previousHeight = 0;
    this.summarizedTabId = undefined;
  }

  getSnapshot() {
    return this.snapshot;
  }

  subscribe(listener) {
    this.listeners.add(listener);
    return () => this.listeners.delete(listener);
  }

  dispatch(action) {
    const next = reducePopupState(this.snapshot, action);
    if (next !== this.snapshot) {
      this.snapshot = next;
      this.listeners.forEach((listener) => listener(next, action));
    }
    return this.snapshot;
  }

  buildSearchUrl(q) {
    return new Promise((resolve) => {
      chrome.runtime.sendMessage({ action: "buildSearchUrl", query: q }, (response) =>
        resolve(response?.url)
      );
    });
  }

  buildDirectionsUrl(origin, destination) {
    return new Promise((resolve) => {
      chrome.runtime.sendMessage(
        { action: "buildDirectionsUrl", origin, destination },
        (response) => resolve(response?.url)
      );
    });
  }

  buildMapsButtonUrl() {
    chrome.runtime.sendMessage({ action: "buildMapsUrl" }, (response) => {
      if (response && response.url) mapsButton.href = response.url;
    });
  }

  updateDimensions(width, height) {
    this.previousWidth = width;
    this.previousHeight = height;
  }
}

State.reduce = reducePopupState;
State.initialSnapshot = initialPopupSnapshot;
State.SUMMARY_TTL_MS = SUMMARY_TTL_MS;
State.isSummaryFresh = isSummaryFresh;

if (typeof module !== "undefined" && module.exports) {
  module.exports = State;
}

// ---- utils/theme.js ----
// Theme Utilities

const ThemeUtils = {
  STORAGE_KEY: "isDarkMode",
  THEME_ATTRIBUTE: "data-theme",
  BS_THEME_ATTRIBUTE: "data-bs-theme",
  DARK: "dark",
  LIGHT: "light",

  getSystemPreference() {
    return window.matchMedia("(prefers-color-scheme: dark)").matches;
  },

  getStoredPreference() {
    return new Promise((resolve) => {
      chrome.storage.local.get(this.STORAGE_KEY, (result) => {
        resolve(result[this.STORAGE_KEY]);
      });
    });
  },

  savePreference(isDarkMode) {
    return new Promise((resolve) => {
      chrome.storage.local.set({ [this.STORAGE_KEY]: isDarkMode }, resolve);
    });
  },

  applyToElement(element, isDarkMode, includeBootstrap = false) {
    if (!element) return;

    const theme = isDarkMode ? this.DARK : this.LIGHT;
    element.setAttribute(this.THEME_ATTRIBUTE, theme);

    if (includeBootstrap) {
      element.setAttribute(this.BS_THEME_ATTRIBUTE, theme);
    }
  },

  async initialize(element, includeBootstrap = false, callback = null) {
    let isDarkMode = await this.getStoredPreference();

    if (isDarkMode === undefined) {
      isDarkMode = this.getSystemPreference();
      await this.savePreference(isDarkMode);
    }

    this.applyToElement(element, isDarkMode, includeBootstrap);

    if (callback) {
      callback(isDarkMode);
    }

    return isDarkMode;
  },

  async toggle(element, includeBootstrap = false, callback = null) {
    const currentValue = (await this.getStoredPreference()) || false;
    const newValue = !currentValue;

    await this.savePreference(newValue);
    this.applyToElement(element, newValue, includeBootstrap);

    if (callback) {
      callback(newValue);
    }

    return newValue;
  },

  notifyContentScript(isDarkMode) {
    chrome.tabs.query({ active: true, currentWindow: true }, (tabs) => {
      if (tabs[0]) {
        chrome.tabs
          .sendMessage(tabs[0].id, {
            action: "updateTheme",
            isDarkMode: isDarkMode,
          })
          .catch(() => {});
      }
    });
  },
};

if (typeof module !== "undefined" && module.exports) {
  module.exports = ThemeUtils;
}

// ---- components/menu.js ----
class ContextMenuUtil {
  static createContextMenu(event, listContainer) {
    event.preventDefault();

    // Prevent context menu in delete mode
    const deleteListButton = document.getElementById("deleteListButton");
    if (deleteListButton && deleteListButton.classList.contains("active-button")) {
      return;
    }

    const clickedItem = event.target.closest(".summary-list, .history-list, .favorite-list");

    const listItems = listContainer.querySelectorAll(
      ".summary-list, .history-list, .favorite-list"
    );

    const existingMenu = document.querySelector(".context-menu");
    if (existingMenu) {
      existingMenu.remove();
    }

    const contextMenu = document.createElement("ul");
    contextMenu.className = "list-group position-absolute rounded-3 context-menu";
    contextMenu.style.left = event.pageX + "px";
    contextMenu.style.top = event.pageY + "px";

    const openAllOption = this.createOption(
      contextMenu,
      `${chrome.i18n.getMessage("openAll")} (${listItems.length})`,
      () => {
        if (window.Analytics)
          window.Analytics.trackFeatureClick("context_menu_open_all", "contextMenu");
        this.openAllUrls(listItems);
      }
    );
    contextMenu.appendChild(openAllOption);

    const canTidy = state.paymentStage?.isTrial || state.paymentStage?.isPremium;
    const tidyLocationsOption = this.createOption(
      contextMenu,
      chrome.i18n.getMessage("tidyLocations"),
      () => {
        if (window.Analytics)
          window.Analytics.trackFeatureClick("context_menu_tidy_locations", "contextMenu");
        if (!canTidy) {
          document.querySelector('[data-bs-target="#premiumModal"]').click();
        } else {
          this.tidyLocations(listItems);
        }
      }
    );

    if (!canTidy) {
      tidyLocationsOption.classList.add("premium-option");
    }

    chrome.storage.local.get("startAddr", ({ startAddr }) => {
      if (clickedItem && startAddr) {
        const getDirectionsOption = this.createOption(
          contextMenu,
          chrome.i18n.getMessage("getDirections"),
          () => {
            if (window.Analytics)
              window.Analytics.trackFeatureClick("context_menu_get_directions", "contextMenu");
            this.getDirections(clickedItem, startAddr);
          }
        );
        contextMenu.appendChild(getDirectionsOption);
      }

      // Append tidy after plan route
      contextMenu.appendChild(tidyLocationsOption);
    });

    document.body.appendChild(contextMenu);

    // Close context menu on outside click
    const closeMenu = (e) => {
      if (!contextMenu.contains(e.target)) {
        contextMenu.remove();
        document.removeEventListener("click", closeMenu);
      }
    };
    setTimeout(() => {
      document.addEventListener("click", closeMenu);
    }, 0);

    return contextMenu;
  }

  static createOption(menu, label, onClick) {
    const option = document.createElement("li");
    option.className =
      "list-group-item list-group-item-action border-0 rounded-2 context-menu-item";
    option.textContent = label;

    option.addEventListener("click", () => {
      onClick();
      menu.remove();
    });

    return option;
  }

  static openAllUrls(listItems) {
    if (!listItems || listItems.length === 0) {
      return;
    }

    const urls = [];
    const { groupTitle, groupColor } = this.getListInfo(listItems[0]);

    const promises = Array.from(listItems).map((item) => {
      const spans = item.querySelectorAll("span");
      const selectedText = Array.from(spans)
        .map((span) => span.textContent)
        .join(" ")
        .trim();
      if (selectedText) {
        return state.buildSearchUrl(selectedText);
      }
      return Promise.resolve(null);
    });

    Promise.all(promises).then((resolvedUrls) => {
      resolvedUrls.forEach((url) => {
        if (url) urls.push(url);
      });

      chrome.runtime.sendMessage({ action: "canGroup" }, (resp) => {
        if (resp && resp.canGroup) {
          chrome.runtime.sendMessage({
            action: "openInGroup",
            urls: urls,
            groupTitle,
            groupColor,
            collapsed: listItems.length > 10 ? true : false,
          });
        } else {
          urls.forEach((url) => chrome.runtime.sendMessage({ action: "openTab", url }));
        }
      });
    });
  }

  static getListInfo(firstItem) {
    if (firstItem.classList.contains("summary-list"))
      return { type: "summary", groupTitle: "✨", groupColor: "purple" };
    if (firstItem.classList.contains("history-list"))
      return { type: "history", groupTitle: "🕓", groupColor: "green" };
    if (firstItem.classList.contains("favorite-list"))
      return { type: "favorite", groupTitle: "🏵️", groupColor: "yellow" };
    return { type: "unknown", groupTitle: "", groupColor: "" };
  }

  static getGroupInfo(firstItem) {
    const { groupTitle, groupColor } = this.getListInfo(firstItem);
    return { groupTitle, groupColor };
  }

  static getDirections(selectedItem, startAddr) {
    const span = selectedItem.querySelector("span");
    const selectedText = span ? span.textContent.trim() : "";

    state.buildDirectionsUrl(startAddr, selectedText).then((directionsUrl) => {
      chrome.tabs.create({ url: directionsUrl });
    });
  }

  static tidyLocations(listItems) {
    this.startBreathingEffect(listItems);

    const locations = Array.from(listItems)
      .map((item) => {
        const spans = item.querySelectorAll("span");
        const locationName = spans[0]?.textContent.trim() || "";
        const locationClue = spans[1]?.textContent.trim() || "";

        return locationName
          ? {
              name: locationName,
              clue: locationClue,
              element: item,
            }
          : null;
      })
      .filter(Boolean);

    chrome.runtime.sendMessage(
      {
        action: "organizeLocations",
        locations,
        listType: this.getListInfo(listItems[0]).type,
      },
      (response) => {
        this.stopBreathingEffect(listItems);

        if (response?.success) {
          this.applyOrganization(response.organizedData, listItems);
        }
      }
    );
  }

  static getListType(firstItem) {
    return this.getListInfo(firstItem).type;
  }

  static applyOrganization(organizedData, listItems) {
    if (!organizedData?.categories) {
      if (organizedData?.rawText) {
        console.log("Raw AI response:", organizedData.rawText);
      }
      return;
    }

    const container = listItems[0]?.parentElement;
    if (!container) {
      console.error("Could not find container for list items");
      return;
    }

    const { elementMap, elementsList } = this.createElementMapping(listItems);

    elementsList.forEach((item) => item.remove());
    const existingHeaders = container.querySelectorAll(".category-header");
    existingHeaders.forEach((header) => header.remove());

    const currentListType = this.getListInfo(elementsList[0]).type;
    const hasFlexReverse = ["history", "favorite"].includes(currentListType);

    this.renderCategories(
      organizedData.categories,
      container,
      elementMap,
      elementsList,
      hasFlexReverse
    );

    this.updateBoundaryItemSpacing(hasFlexReverse, container);

    measureContentSize();
  }

  static createElementMapping(listItems) {
    const elementMap = new Map();
    const elementsList = Array.from(listItems);

    elementsList.forEach((item, index) => {
      const locationName = item.querySelector("span")?.textContent.trim();
      if (!locationName) return;

      // Robust mapping strategies
      const mappings = [
        locationName,
        locationName.toLowerCase().replace(/\s+/g, " ").trim(),
        `index_${index}`,
      ];

      mappings.forEach((key) => elementMap.set(key, item));
    });

    return { elementMap, elementsList };
  }

  static renderCategories(categories, container, elementMap, elementsList, hasFlexReverse) {
    categories.forEach((category) => {
      const categoryHeader = this.createCategoryHeader(category.name);

      // Add header based on layout
      if (!hasFlexReverse) {
        container.appendChild(categoryHeader);
      }

      category.locations.forEach((location) => {
        const element = this.findMatchingElement(location.name, elementMap, elementsList);
        if (element) {
          element.classList.add("mb-3");
          container.appendChild(element);
        }
      });

      if (hasFlexReverse) {
        container.appendChild(categoryHeader);
      }
    });
  }

  static createCategoryHeader(categoryName) {
    const header = document.createElement("div");
    header.className = "category-header";

    const text = document.createElement("span");
    text.textContent = categoryName;

    header.appendChild(text);
    return header;
  }

  static findMatchingElement(locationName, elementMap, elementsList) {
    let element = elementMap.get(locationName);
    if (element) return element;

    const normalized = locationName.toLowerCase().replace(/\s+/g, " ").trim();
    element = elementMap.get(normalized);
    if (element) return element;

    for (const [key, el] of elementMap.entries()) {
      if (!key.startsWith("index_") && key.includes(normalized)) {
        return el;
      }
    }

    return elementsList.find((item) => {
      const itemText = item.querySelector("span")?.textContent.trim() || "";
      return (
        itemText.toLowerCase().includes(normalized) || normalized.includes(itemText.toLowerCase())
      );
    });
  }

  static updateBoundaryItemSpacing(hasFlexReverse, container) {
    if (!container) return;

    const currentItems = container.querySelectorAll(".list-group-item");

    if (currentItems.length === 0) return;

    let targetItem = hasFlexReverse
      ? container.querySelector(".list-group-item:first-child")
      : container.querySelector(".list-group-item:last-child");

    if (targetItem) {
      targetItem.classList.remove("mb-3");
    }
  }

  static breathingInterval = null;

  static startBreathingEffect(listItems) {
    const listContainer = listItems[0]?.parentElement;
    if (!listContainer) return;

    let opacity = 1;
    let decreasing = true;

    this.breathingInterval = setInterval(() => {
      if (decreasing) {
        opacity -= 0.08;
        if (opacity <= 0.4) {
          decreasing = false;
        }
      } else {
        opacity += 0.08;
        if (opacity >= 1) {
          setTimeout(() => {
            decreasing = true;
          }, 200);
        }
      }
      listContainer.style.opacity = opacity;
    }, 100);
  }

  static stopBreathingEffect(listItems) {
    if (this.breathingInterval) {
      clearInterval(this.breathingInterval);
      this.breathingInterval = null;
    }

    const listContainer = listItems[0]?.parentElement;
    if (listContainer) {
      listContainer.style.opacity = "";
    }
  }
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = ContextMenuUtil;
}

// ---- components/remove.js ----
class Remove {
  addRemoveListener() {
    cancelButton.addEventListener("click", () => {
      if (window.Analytics) window.Analytics.trackFeatureClick("cancel_delete", "cancelButton");
      this.backToNormal();
    });

    deleteButton.addEventListener("click", () => {
      if (window.Analytics) window.Analytics.trackFeatureClick("delete_items", "deleteButton");
      if (state.getSnapshot().deleteMode.source === "history") {
        this.deleteFromHistoryList();
      } else {
        this.deleteFromFavoriteList();
      }
      this.backToNormal();
    });

    deleteListButton.addEventListener("click", () => {
      if (window.Analytics) window.Analytics.trackFeatureClick("delete_mode", "deleteListButton");
      const snapshot = state.getSnapshot();
      state.dispatch(
        snapshot.deleteMode.source
          ? { type: "DELETE_CANCEL" }
          : { type: "DELETE_ENTER", source: snapshot.activeTab }
      );
    });

    [searchHistoryListContainer, favoriteListContainer].forEach((container) => {
      container.addEventListener("change", (event) => {
        if (!event.target.classList.contains("form-check-input")) return;
        const li = event.target.closest("li");
        if (li) state.dispatch({ type: "DELETE_TOGGLE", value: li.dataset.itemValue || "" });
      });
    });
  }

  deleteFromHistoryList() {
    const snapshot = state.getSnapshot();
    const selected = new Set(snapshot.deleteMode.selectedValues);
    const items = snapshot.history.items.filter((item) => !selected.has(item));
    state.dispatch({ type: "HISTORY_SET", items, emptyReason: "cleared" });
    state.dispatch({ type: "DELETE_CANCEL" });
    // Re-read to avoid clobbering concurrent writes
    chrome.storage.local.get("searchHistoryList", ({ searchHistoryList }) => {
      const latest = Array.isArray(searchHistoryList) ? searchHistoryList : [];
      chrome.storage.local.set({ searchHistoryList: latest.filter((item) => !selected.has(item)) });
    });
  }

  deleteFromFavoriteList() {
    const snapshot = state.getSnapshot();
    const selected = new Set(snapshot.deleteMode.selectedValues);
    const items = snapshot.favorite.items.filter((item) => !selected.has(item));
    state.dispatch({ type: "FAVORITE_SET", items });
    state.dispatch({ type: "DELETE_CANCEL" });
    // Goes through favorite's write queue so this can't race a concurrent
    // single-item removal (favorite.removeFavoriteItem) on the same key.
    favorite.queueFavoriteWrite((latest) => latest.filter((item) => !selected.has(item)));
  }

  backToNormal() {
    state.dispatch({ type: "DELETE_CANCEL" });
  }

  render(snapshot) {
    const deleteModeButton = deleteListButton;
    const deleteActions = deleteButtonGroup;
    const historyActions = searchButtonGroup;
    const favoriteActions = exportButtonGroup;
    const historyTabButton = searchHistoryButton;
    const favoriteTabButton = favoriteListButton;
    const summaryTabButton = geminiSummaryButton;
    const deleteAction = deleteButton;
    const deleteLabel = deleteAction?.querySelector("span");
    if (!deleteModeButton || !deleteActions || !historyActions || !favoriteActions) return;

    const { source, selectedValues } = snapshot.deleteMode;
    const deleting = Boolean(source);
    deleteModeButton.classList.toggle("active-button", deleting);
    deleteActions.classList.toggle("d-none", !deleting);
    historyActions.classList.toggle("d-none", snapshot.activeTab !== "history" || deleting);
    favoriteActions.classList.toggle("d-none", snapshot.activeTab !== "favorite" || deleting);
    geminiButtonGroup?.classList.toggle("d-none", snapshot.activeTab !== "gemini");

    if (historyTabButton) historyTabButton.disabled = deleting && source !== "history";
    if (favoriteTabButton) favoriteTabButton.disabled = deleting && source !== "favorite";
    if (summaryTabButton) summaryTabButton.disabled = deleting;

    const count = selectedValues.length;
    if (deleteLabel) {
      deleteLabel.textContent = chrome.i18n.getMessage(
        count ? "deleteBtnText" : "deleteBtnTextEmpty",
        count ? String(count) : undefined
      );
    }
    deleteAction?.classList.toggle("disabled", count === 0);
  }
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = Remove;
}

// ---- components/favorite.js ----
class Favorite {
  addFavoritePageListener() {
    exportButton.addEventListener("click", () => {
      if (window.Analytics) window.Analytics.trackFeatureClick("export_favorite", "exportButton");
      chrome.storage.local.get(["favoriteList"], ({ favoriteList }) => {
        if (!favoriteList || !Array.isArray(favoriteList)) {
          return;
        }

        const escapeCSV = (str) => {
          if (str.includes(",") || str.includes('"') || str.includes("\n")) {
            return `"${str.replace(/"/g, '""')}"`;
          }
          return str;
        };
        const trimmedFavorite = favoriteList.map((item) => item.split(" @")[0]);
        const csv = "name\n" + trimmedFavorite.map((item) => `${escapeCSV(item)}`).join("\n");

        // UTF-8 BOM for Excel non-ASCII support
        const blob = new Blob(["\uFEFF" + csv], {
          type: "text/csv; charset=utf-8;",
        });

        const a = document.createElement("a");
        a.href = URL.createObjectURL(blob);
        a.download = "TheMapsExpress_FavoriteList.csv";
        a.click();
      });
    });

    importButton.addEventListener("click", () => {
      if (window.Analytics) window.Analytics.trackFeatureClick("import_favorite", "importButton");
      fileInput.click();
    });

    fileInput.addEventListener("change", (event) => {
      const file = event.target.files[0];
      if (!file) return;
      if (window.Analytics) window.Analytics.trackFeatureClick("file_imported", "fileInput");

      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          let importedData = [];
          const fileContent = event.target.result;

          if (fileContent && fileContent.length > 0) {
            const rows = this.parseCSV(fileContent);
            importedData = rows
              .slice(1)
              .map((row) => (row[0] || "").trim())
              .filter((name) => name.length > 0);
          }

          chrome.storage.local.get(["favoriteList"], ({ favoriteList }) => {
            // Merge without overwrite, dedupe by name ignoring "@clue"
            const existingList = Array.isArray(favoriteList) ? favoriteList : [];
            const existingNames = new Set(existingList.map((item) => item.split(" @")[0]));
            const newNames = [];
            importedData.forEach((name) => {
              if (!existingNames.has(name) && !newNames.includes(name)) {
                newNames.push(name);
              }
            });
            const mergedList = existingList.concat(newNames);

            chrome.storage.local.set({ favoriteList: mergedList }, () => {
              state.dispatch({ type: "FAVORITE_SET", items: mergedList });
            });
          });
        } catch (error) {
          state.dispatch({ type: "FAVORITE_ERROR", errorKey: "importErrorMsg" });
        }
      };

      reader.readAsText(file);

      // Allow re-selecting same file
      event.target.value = "";
    });

    favoriteListContainer.addEventListener("mousedown", (event) => {
      const liElement = DOMUtils.findClosestListItem(event);
      if (!liElement) return;

      if (
        state.getSnapshot().deleteMode.source === "favorite" ||
        liElement.classList.contains("delete-list")
      ) {
        if (event.target.classList.contains("form-check-input")) {
          return;
        } else {
          state.dispatch({ type: "DELETE_TOGGLE", value: liElement.dataset.itemValue || "" });
        }
      } else {
        if (event.target.classList.contains("form-check-input")) {
          return;
        }

        if (event.target.classList.contains("bi")) {
          if (event.button !== 0) return;
          if (window.Analytics)
            window.Analytics.trackFeatureClick("remove_favorite_item", "favoriteListContainer");
          this.removeFavoriteItem(liElement.dataset.itemValue || "", event);
          return;
        }

        const spans = liElement.querySelectorAll("span");
        const selectedText = Array.from(spans)
          .map((span) => span.textContent)
          .join(" ")
          .trim();

        state.buildSearchUrl(selectedText).then((searchUrl) => {
          if (window.Analytics)
            window.Analytics.trackFeatureClick("click_favorite_item", "favoriteListContainer");
          if (event.button === 1) {
            event.preventDefault();
            chrome.runtime.sendMessage({ action: "openTab", url: searchUrl });
          } else if (event.button === 0) {
            window.open(searchUrl, "_blank");
          }
        });
      }
    });

    favoriteListContainer.addEventListener("contextmenu", (event) => {
      ContextMenuUtil.createContextMenu(event, favoriteListContainer);
    });
  }

  // Minimal RFC 4180 parser matching export format
  parseCSV(content) {
    const rows = [];
    let row = [];
    let field = "";
    let inQuotes = false;

    for (let i = 0; i < content.length; i++) {
      const ch = content[i];

      if (inQuotes) {
        if (ch === '"') {
          if (content[i + 1] === '"') {
            field += '"';
            i++;
          } else {
            inQuotes = false;
          }
        } else {
          field += ch;
        }
      } else if (ch === '"') {
        inQuotes = true;
      } else if (ch === ",") {
        row.push(field);
        field = "";
      } else if (ch === "\n" || ch === "\r") {
        if (ch === "\r" && content[i + 1] === "\n") i++;
        row.push(field);
        rows.push(row);
        row = [];
        field = "";
      } else {
        field += ch;
      }
    }

    if (field !== "" || row.length > 0) {
      row.push(field);
      rows.push(row);
    }

    return rows.filter((r) => r.some((f) => f.trim().length > 0));
  }

  createFavoriteIcon(itemName, favoriteList) {
    const matched = Boolean(favoriteList && favoriteList.includes(itemName));
    const favoriteIcon = document.createElement("i");
    favoriteIcon.className = matched ? "bi bi-patch-check-fill matched" : "bi bi-patch-plus-fill";
    favoriteIcon.title = chrome.i18n.getMessage(matched ? "removeFavoriteLabel" : "plusLabel");
    return favoriteIcon;
  }

  addToFavoriteList(selectedText) {
    // Runs through the same write queue as removeFavoriteItem (rather than a
    // separate background.js round-trip) so an add and a remove can never
    // race each other and silently drop one of the two changes.
    this.queueFavoriteWrite((latest) => {
      const next = latest.filter((item) => item !== selectedText);
      next.push(selectedText);
      return next;
    });
  }

  // Chain get-then-set writes to favoriteList so each get() reads storage after
  // the previous set() has landed, avoiding a lost update when several writes
  // happen in quick succession. Recovers on failure instead of permanently
  // blocking every later call behind a rejected promise.
  queueFavoriteWrite(computeNext) {
    this._favoriteWriteQueue = (this._favoriteWriteQueue || Promise.resolve())
      .then(
        () =>
          new Promise((resolve) => {
            chrome.storage.local.get("favoriteList", ({ favoriteList }) => {
              const latest = Array.isArray(favoriteList) ? favoriteList : [];
              chrome.storage.local.set({ favoriteList: computeNext(latest) }, resolve);
            });
          })
      )
      .catch((error) => {
        console.error("Failed to persist favoriteList change:", error);
        this._favoriteWriteQueue = Promise.resolve();
      });
    return this._favoriteWriteQueue;
  }

  removeFavoriteItem(itemValue, event) {
    if (!itemValue) return;

    // Ignore a second removal within 300ms at nearly the same screen position:
    // the list re-renders synchronously on removal, so a fast double-click can
    // otherwise land on a different item that reflowed into the same spot.
    const now = Date.now();
    const last = this._lastFavoriteRemoveClick;
    if (
      last &&
      now - last.time < 300 &&
      Math.abs(event.clientX - last.x) < 10 &&
      Math.abs(event.clientY - last.y) < 10
    ) {
      return;
    }
    this._lastFavoriteRemoveClick = { time: now, x: event.clientX, y: event.clientY };

    const items = state.getSnapshot().favorite.items.filter((item) => item !== itemValue);
    state.dispatch({ type: "FAVORITE_SET", items });

    this.queueFavoriteWrite((latest) => latest.filter((item) => item !== itemValue));
  }

  updateFavorite(favoriteList) {
    state.dispatch({ type: "FAVORITE_SET", items: favoriteList });
  }

  render(snapshot) {
    const container = favoriteListContainer;
    const statusMessage = favoriteEmptyMessage;
    const exportAction = exportButton;
    if (!container || !statusMessage || !exportAction) return;
    const { items, status, errorKey } = snapshot.favorite;
    const selected = new Set(snapshot.deleteMode.selectedValues);
    const deleting = snapshot.deleteMode.source === "favorite";

    container.replaceChildren();
    statusMessage.style.whiteSpace = "pre-line";
    statusMessage.textContent = chrome.i18n.getMessage(
      status === "error" ? errorKey || "importErrorMsg" : "favoriteEmptyMsg"
    );
    statusMessage.classList.toggle("d-none", items.length > 0 && status !== "error");

    if (items.length > 0 && status !== "error") {
      const ul = document.createElement("ul");
      ul.className = "list-group d-flex flex-column-reverse";
      items.forEach((selectedText) => {
        const li = document.createElement("li");
        li.className =
          "list-group-item border rounded mb-3 px-3 d-flex justify-content-between align-items-center text-break";
        li.dataset.itemValue = selectedText;

        const [name, clue] = selectedText.split(" @");
        const span = document.createElement("span");
        span.textContent = name;
        li.appendChild(span);
        if (clue !== undefined) {
          const clueSpan = document.createElement("span");
          clueSpan.className = "d-none";
          clueSpan.textContent = clue;
          li.appendChild(clueSpan);
        }

        const icon = document.createElement("i");
        icon.className = "bi bi-patch-check-fill matched";
        icon.classList.toggle("d-none", deleting);
        icon.title = chrome.i18n.getMessage("removeFavoriteLabel");
        li.appendChild(icon);

        const checkbox = document.createElement("input");
        checkbox.className = "form-check-input";
        checkbox.classList.toggle("d-none", !deleting);
        checkbox.type = "checkbox";
        checkbox.checked = selected.has(selectedText);
        checkbox.ariaLabel = "Delete";
        li.appendChild(checkbox);

        li.classList.toggle("favorite-list", !deleting);
        li.classList.toggle("delete-list", deleting);
        li.classList.toggle("checked-list", selected.has(selectedText));
        ul.appendChild(li);
      });
      ul.firstElementChild?.classList.remove("mb-3");
      container.appendChild(ul);
    }

    exportAction.disabled = items.length === 0;
  }
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = Favorite;
}

// ---- components/history.js ----
class History {
  constructor() {
    this._undoWindow = new UndoWindow(() => this.render(state.getSnapshot()));
  }

  addHistoryPageListener() {
    searchHistoryListContainer.addEventListener("mousedown", (event) => {
      const liElement = DOMUtils.findClosestListItem(event);
      if (!liElement) return;

      // Swallow clicks on fake onboarding demo item to prevent persistence
      if (liElement.classList.contains("onboarding-demo-item")) {
        event.stopPropagation();
        event.preventDefault();
        if (event.target.classList.contains("bi") && onboarding) onboarding.next();
        return;
      }

      if (
        state.getSnapshot().deleteMode.source === "history" ||
        liElement.classList.contains("delete-list")
      ) {
        if (event.target.classList.contains("form-check-input")) {
          return;
        } else {
          state.dispatch({ type: "DELETE_TOGGLE", value: liElement.dataset.itemValue || "" });
        }
      } else {
        if (event.target.classList.contains("form-check-input")) {
          return;
        }

        if (event.target.classList.contains("bi")) {
          // Icon is mid fade-out from a previous removal; ignore re-clicks
          // until mouseleave restores it (see DOMUtils.fadeOutFavoriteIcon).
          if (event.target.classList.contains("unfavoriting")) return;
          if (event.button !== 0) return;

          const selectedText = liElement.querySelector("span")?.textContent;

          if (event.target.classList.contains("matched")) {
            if (window.Analytics)
              window.Analytics.trackFeatureClick(
                "remove_favorite_from_history",
                "searchHistoryListContainer"
              );
            favorite.removeFavoriteItem(liElement.dataset.itemValue || "", event);
            DOMUtils.fadeOutFavoriteIcon(event.target);
          } else {
            if (window.Analytics)
              window.Analytics.trackFeatureClick(
                "add_to_favorite_from_history",
                "searchHistoryListContainer"
              );
            favorite.addToFavoriteList(selectedText);
            DOMUtils.animateFavoriteIcon(event.target);
          }
          return;
        }

        const selectedText = liElement.querySelector("span")?.textContent;

        state
          .buildSearchUrl(selectedText)
          .then((searchUrl) => {
            if (window.Analytics)
              window.Analytics.trackFeatureClick(
                "click_history_item",
                "searchHistoryListContainer"
              );
            if (event.button === 1) {
              event.preventDefault();
              chrome.runtime.sendMessage({ action: "openTab", url: searchUrl });
            } else if (event.button === 0) {
              window.open(searchUrl, "_blank");
            }
          })
          .catch((error) => {
            console.error("Failed to build search URL:", error);
          });
      }
    });

    searchHistoryListContainer.addEventListener("contextmenu", (event) => {
      const liElement = DOMUtils.findClosestListItem(event);
      if (liElement?.classList.contains("onboarding-demo-item")) {
        event.preventDefault();
        return;
      }
      ContextMenuUtil.createContextMenu(event, searchHistoryListContainer);
    });

    clearButton.addEventListener("click", () => {
      if (window.Analytics) window.Analytics.trackFeatureClick("clear_history", "clearButton");
      const clearedItems = state.getSnapshot().history.items;

      chrome.storage.local.set({ searchHistoryList: [] });
      state.dispatch({ type: "HISTORY_SET", items: [], emptyReason: "cleared" });

      if (clearedItems.length > 0) this._startUndoWindow(clearedItems);
    });

    undoButtonHistory.addEventListener("click", () => {
      if (window.Analytics)
        window.Analytics.trackFeatureClick("undo_clear_history", "undoButtonHistory");
      this._undoClear();
    });
  }

  // Swaps clearButton for undoButtonHistory; reverts after 6s if unused.
  _startUndoWindow(clearedItems) {
    this._undoWindow.start(clearedItems);
    this.render(state.getSnapshot());
  }

  _undoClear() {
    const items = this._undoWindow.consume();
    if (!items) return;

    chrome.storage.local.set({ searchHistoryList: items });
    state.dispatch({ type: "HISTORY_SET", items });
  }

  createListItem(itemName, favoriteList) {
    const li = document.createElement("li");
    li.className =
      "list-group-item border rounded mb-3 px-3 history-list d-flex justify-content-between align-items-center text-break";

    const span = document.createElement("span");
    span.textContent = itemName;
    li.appendChild(span);

    const icon = (this.favoriteComponent || favorite).createFavoriteIcon(itemName, favoriteList);
    li.appendChild(icon);

    const checkbox = document.createElement("input");
    checkbox.className = "form-check-input d-none";
    checkbox.type = "checkbox";
    checkbox.value = "delete";
    checkbox.name = "checkDelete";
    checkbox.ariaLabel = "Delete";
    checkbox.style.cursor = "pointer";
    li.appendChild(checkbox);

    return li;
  }

  render(snapshot, meta = {}) {
    const container = searchHistoryListContainer;
    const statusMessage = emptyMessage;
    const clearAction = clearButton;
    const undoAction = undoButtonHistory;
    if (!container || !statusMessage || !clearAction || !undoAction) return;
    const { items, emptyReason } = snapshot.history;
    const selected = new Set(snapshot.deleteMode.selectedValues);
    const deleting = snapshot.deleteMode.source === "history";
    const showDemo = snapshot.onboarding.demoHistoryVisible;
    const undoing = Boolean(this._undoWindow.pending) && items.length === 0;

    statusMessage.style.whiteSpace = "pre-line";
    statusMessage.textContent = chrome.i18n.getMessage(
      emptyReason === "cleared" ? "clearedUpMsg" : "historyEmptyMsg"
    );
    statusMessage.classList.toggle("d-none", items.length > 0 || showDemo);
    clearAction.disabled = items.length === 0;
    clearAction.classList.toggle("d-none", undoing);
    undoAction.classList.toggle("d-none", !undoing);

    // Patch icon classNames in place to preserve animation
    const structuralChange =
      meta.historyChanged !== false ||
      meta.deleteModeChanged !== false ||
      meta.onboardingChanged !== false;
    const existingItems = structuralChange ? [] : container.querySelectorAll("li[data-item-value]");

    if (!structuralChange && existingItems.length > 0) {
      existingItems.forEach((li) => {
        const icon = li.querySelector("i");
        if (
          !icon ||
          icon.classList.contains("spring-animation") ||
          icon.classList.contains("unfavoriting")
        )
          return;
        const newIcon = (this.favoriteComponent || favorite).createFavoriteIcon(
          li.dataset.itemValue,
          snapshot.favorite.items
        );
        if (icon.className !== newIcon.className) {
          icon.className = newIcon.className;
          icon.classList.toggle("d-none", deleting);
        }
        icon.title = newIcon.title;
      });
      return;
    }

    container.replaceChildren();

    if (items.length > 0 || showDemo) {
      const ul = document.createElement("ul");
      ul.className = "list-group d-flex flex-column-reverse";
      items.forEach((item) => {
        const li = this.createListItem(item, snapshot.favorite.items);
        li.dataset.itemValue = item;
        const checkbox = li.querySelector("input");
        const icon = li.querySelector("i");
        checkbox?.classList.toggle("d-none", !deleting);
        if (checkbox) checkbox.checked = selected.has(item);
        icon?.classList.toggle("d-none", deleting);
        li.classList.toggle("history-list", !deleting);
        li.classList.toggle("delete-list", deleting);
        li.classList.toggle("checked-list", selected.has(item));
        ul.appendChild(li);
      });
      if (showDemo) {
        const demoName = chrome.i18n.getMessage("onboardingDemoPlace") || "Eiffel Tower";
        const li = this.createListItem(demoName, snapshot.favorite.items);
        li.classList.add("onboarding-demo-item");
        li.dataset.itemValue = demoName;
        ul.appendChild(li);
      }
      ul.firstElementChild?.classList.remove("mb-3");
      container.appendChild(ul);
    }
  }
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = History;
}

// ---- components/gemini.js ----
class Gemini {
  constructor() {
    this.apiToken = 0;
    this.videoToken = 0;
    this.summarySequence = 0;
    this._undoWindow = new UndoWindow(() => this.render(this.getStore().getSnapshot()));
  }

  getStore() {
    return this.store || state;
  }

  nextSummaryRequestId() {
    this.summarySequence += 1;
    return `summary-${Date.now()}-${this.summarySequence}`;
  }

  beginSummary(originTabId = null) {
    const requestId = this.nextSummaryRequestId();
    this.getStore().dispatch({ type: "SUMMARY_START", requestId, originTabId });
    chrome.storage.local.remove(["summaryList", "timestamp"]);
    return requestId;
  }

  addGeminiPageListener() {
    summaryListContainer.addEventListener("click", (event) => {
      const liElement = DOMUtils.findClosestListItem(event);
      if (!liElement) return;

      const spans = liElement.querySelectorAll("span");

      if (event.target.classList.contains("bi")) {
        // Icon is mid fade-out from a previous removal; ignore re-clicks
        // until mouseleave restores it (see DOMUtils.fadeOutFavoriteIcon).
        if (event.target.classList.contains("unfavoriting")) return;
        if (event.button !== 0) return;

        const nameSpan = spans[0].textContent;
        const reconstructedValue =
          spans.length >= 2 ? nameSpan + " @" + spans[1].textContent : nameSpan;

        if (event.target.classList.contains("matched")) {
          // "matched" is determined by name only (ignoring clue), so the
          // stored favorite may carry a different clue than this summary
          // item's own reconstructed value. Prefer an exact name+clue match
          // first — that's unambiguously this item — and only fall back to
          // matching by name when no exact match exists (e.g. this item's
          // stored favorite was saved with a different clue).
          const favoriteItems = this.getStore().getSnapshot().favorite.items;
          const storedItem =
            favoriteItems.find((item) => item === reconstructedValue) ||
            favoriteItems.find((item) => item.split(" @")[0] === nameSpan) ||
            reconstructedValue;

          if (window.Analytics)
            window.Analytics.trackFeatureClick(
              "remove_favorite_from_summary",
              "summaryListContainer"
            );
          favorite.removeFavoriteItem(storedItem, event);
          DOMUtils.fadeOutFavoriteIcon(event.target);
        } else {
          if (window.Analytics)
            window.Analytics.trackFeatureClick(
              "add_to_favorite_from_summary",
              "summaryListContainer"
            );
          favorite.addToFavoriteList(reconstructedValue);
          DOMUtils.animateFavoriteIcon(event.target);
        }
        return;
      }

      const selectedText = Array.from(spans)
        .map((span) => span.textContent)
        .join(" ")
        .trim();

      this.getStore()
        .buildSearchUrl(selectedText)
        .then((searchUrl) => {
          if (window.Analytics)
            window.Analytics.trackFeatureClick("click_summary_item", "summaryListContainer");
          chrome.runtime.sendMessage({ action: "openTab", url: searchUrl });
        });
    });

    summaryListContainer.addEventListener("contextmenu", (event) => {
      ContextMenuUtil.createContextMenu(event, summaryListContainer);
    });

    clearButtonSummary.addEventListener("click", () => {
      if (window.Analytics)
        window.Analytics.trackFeatureClick("clear_summary", "clearButtonSummary");
      const { items, timestamp } = this.getStore().getSnapshot().summary;

      chrome.storage.local.remove(["summaryList", "timestamp"]);
      this.getStore().dispatch({ type: "SUMMARY_CLEAR" });

      if (items.length > 0) this._startUndoWindow(items, timestamp);
    });

    undoButtonSummary.addEventListener("click", () => {
      if (window.Analytics)
        window.Analytics.trackFeatureClick("undo_clear_summary", "undoButtonSummary");
      this._undoClear();
    });

    videoSummaryButton.addEventListener("click", () => {
      if (window.Analytics)
        window.Analytics.trackFeatureClick("video_summary_toggle", "videoSummaryButton");
      const enabled = !this.getStore().getSnapshot().video.enabled;
      this.getStore().dispatch({ type: "VIDEO_TOGGLE", enabled });

      chrome.storage.local.set({ videoSummaryToggle: enabled });
      videoSummaryButton.classList.toggle("no-hover-temp", !enabled);
    });

    // Hover disable effect for videoSummaryButton
    videoSummaryButton.addEventListener("mouseleave", () => {
      if (videoSummaryButton.classList.contains("no-hover-temp")) {
        videoSummaryButton.classList.remove("no-hover-temp");
      }
    });

    sendButton.addEventListener("click", () => {
      if (window.Analytics) window.Analytics.trackFeatureClick("send_gemini", "sendButton");
      if (this.getStore().getSnapshot().summary.phase === "generating") return;
      const requestId = this.beginSummary(null);
      chrome.tabs.query({ active: true, currentWindow: true }, (tabs) => {
        if (!tabs.length) {
          this.ResponseErrorMsg(null, requestId);
          return;
        }
        this.getStore().dispatch({ type: "SUMMARY_START", requestId, originTabId: tabs[0].id });
        const video = this.getStore().getSnapshot().video;
        if (video.enabled && video.available) {
          this.summarizeFromGeminiVideoUnderstanding(
            this.normalizeYoutubeUrl(tabs[0].url),
            requestId
          );
        } else {
          this.performNormalContentSummary(requestId, tabs[0]);
        }
      });
    });
  }

  // Swaps clearButtonSummary for undoButtonSummary; reverts after 6s if unused.
  _startUndoWindow(items, timestamp) {
    this._undoWindow.start({ items, timestamp });
    this.render(this.getStore().getSnapshot());
  }

  _undoClear() {
    const pending = this._undoWindow.consume();
    if (!pending) return;

    // SUMMARY_STORAGE_SET itself is a no-op while generating (see reducer), but
    // the storage write isn't guarded there — skip it too, or a failed generate
    // leaves stale pre-clear data in storage that resurrects on next popup open.
    if (this.getStore().getSnapshot().summary.phase === "generating") return;

    chrome.storage.local.set({ summaryList: pending.items, timestamp: pending.timestamp });
    this.getStore().dispatch({
      type: "SUMMARY_STORAGE_SET",
      items: pending.items,
      timestamp: pending.timestamp,
    });
  }

  fetchAPIKey(apiKey) {
    apiInput.placeholder = chrome.i18n.getMessage("apiPlaceholder");
    const token = ++this.apiToken;
    this.getStore().dispatch({ type: "API_VERIFY_START", token, hasKey: Boolean(apiKey) });

    if (apiKey) {
      chrome.runtime.sendMessage({ action: "verifyApiKey", apiKey }, ({ valid, error } = {}) => {
        this.getStore().dispatch({
          type: "API_VERIFY_RESULT",
          token,
          valid: !error && Boolean(valid),
        });
        if (!error && valid) {
          apiInput.placeholder = "............" + apiKey.slice(-4);
        }
      });
    }
  }

  async checkCurrentTabForYoutube() {
    const token = ++this.videoToken;
    this.getStore().dispatch({ type: "VIDEO_CONTEXT_REQUEST", token });
    const tabs = (await chrome.tabs.query({ active: true, currentWindow: true })) || [];
    const currentTabUrl = tabs[0]?.url || "";
    const youtubeMatch = currentTabUrl.match(/youtube\.com\/(?:watch\?v=|shorts\/)(.{11})/);

    if (youtubeMatch) {
      const videoId = youtubeMatch[1];
      this.getStore().dispatch({ type: "VIDEO_CONTEXT_RESULT", token, available: true });

      this.scrapeLen(videoId)
        .then((videoLength) => {
          if (token === this.videoToken) {
            chrome.storage.local.set({
              currentVideoInfo: {
                videoId,
                length: videoLength,
              },
            });
          }
        })
        .catch((error) => console.error("Error scraping video length:", error));
    } else {
      this.getStore().dispatch({ type: "VIDEO_CONTEXT_RESULT", token, available: false });
      chrome.storage.local.remove("currentVideoInfo");
    }

    // Token prevents stale tab callbacks
  }

  async scrapeLen(id) {
    try {
      const html = await fetch(`https://www.youtube.com/watch?v=${id}`, {
        credentials: "omit",
      }).then((r) => r.text());
      const m = html.match(/"lengthSeconds":"(\d+)"/);
      return m ? Number(m[1]) : null;
    } catch (error) {
      console.error("Failed to scrape video length:", error);
      return null;
    }
  }

  // Clear stale summary data
  clearExpiredSummary() {
    chrome.storage.local.get(["summaryList", "timestamp", "favoriteList"], (result) => {
      const items = Array.isArray(result.summaryList) ? result.summaryList : [];
      const timestamp = Number(result.timestamp);
      const now = Date.now();
      if (State.isSummaryFresh(items, timestamp, now)) {
        this.getStore().dispatch({ type: "SUMMARY_STORAGE_SET", items, timestamp });
      } else {
        this.getStore().dispatch({ type: "SUMMARY_STORAGE_SET", items: [] });
        if (items.length || result.timestamp != null) {
          chrome.storage.local.remove(["summaryList", "timestamp"]);
        }
      }
    });
  }

  // Parse LLM output to prevent prompt injection
  parseSummaryItems(response) {
    const doc = new DOMParser().parseFromString(response, "text/html");
    const normalize = (text) => text.replace(/\s+/g, " ").trim();
    const items = [];
    doc.querySelectorAll("li").forEach((li) => {
      const spans = Array.from(li.children).filter((el) => el.tagName === "SPAN");
      const name = normalize(spans[0] ? spans[0].textContent : li.textContent);
      const clue = spans[1] ? normalize(spans[1].textContent) : "";
      if (name) items.push({ name, clue });
    });
    return items;
  }

  buildSummaryListElement(summaryList) {
    const ul = document.createElement("ul");
    ul.className = "list-group d-flex";

    summaryList.forEach((item, index) => {
      const isLastItem = index === summaryList.length - 1;
      const li = document.createElement("li");
      li.className =
        "list-group-item border rounded px-3 summary-list d-flex justify-content-between align-items-center text-break" +
        (isLastItem ? "" : " mb-3");

      const nameSpan = document.createElement("span");
      nameSpan.textContent = item.name ?? "";
      const clueSpan = document.createElement("span");
      clueSpan.className = "d-none";
      clueSpan.textContent = item.clue ?? "";
      const icon = document.createElement("i");
      icon.className = "bi";

      li.append(nameSpan, clueSpan, icon);
      ul.appendChild(li);
    });

    return ul;
  }

  constructSummaryHTML(summaryList, favoriteList = []) {
    summaryListContainer.replaceChildren(this.buildSummaryListElement(summaryList));
    this.updateSummaryFavoriteIcons(favoriteList);

    return summaryListContainer.innerHTML;
  }

  updateSummaryFavoriteIcons(favoriteList = []) {
    const summaryItems = summaryListContainer.querySelectorAll(".summary-list");
    const trimmedFavorite = favoriteList.map((item) => item.split(" @")[0]);

    summaryItems.forEach((item) => {
      const itemName = item.querySelector("span:first-child").textContent;
      const existingIcon = item.querySelector("i");

      if (existingIcon) {
        const newIcon = favorite.createFavoriteIcon(itemName, trimmedFavorite);
        existingIcon.className = newIcon.className;
        existingIcon.title = newIcon.title;
      }
    });
  }

  // Strip query params for canonical YouTube URL
  normalizeYoutubeUrl(url) {
    const match = url.match(/youtube\.com\/(watch\?v=|shorts\/)(.{11})/);
    if (!match) return url;
    return match[1] === "shorts/"
      ? `https://www.youtube.com/shorts/${match[2]}`
      : `https://www.youtube.com/watch?v=${match[2]}`;
  }

  summarizeFromGeminiVideoUnderstanding(videoUrl, requestId = null) {
    requestId = requestId || this.beginSummary(null);

    chrome.storage.local.get("currentVideoInfo", ({ currentVideoInfo }) => {
      if (currentVideoInfo && currentVideoInfo.length) {
        const estTime = Math.ceil(currentVideoInfo.length / 30);
        this.getStore().dispatch({
          type: "SUMMARY_ESTIMATE",
          requestId,
          estimateSeconds: estTime,
        });
      }
    });

    chrome.runtime.sendMessage({ action: "summarizeVideo", text: videoUrl }, (response) => {
      // Success on <ul> fragment
      if (typeof response === "string") {
        try {
          this.createSummaryList(response, requestId);
        } catch (error) {
          this.ResponseErrorMsg({ error: String(error) }, requestId);
        }
      } else {
        this.ResponseErrorMsg(response, requestId);
      }
    });
  }

  performNormalContentSummary(requestId = null, knownTab = null) {
    chrome.runtime.sendMessage({ action: "getApiKey" }, (res) => {
      const apiKey = res ? res.apiKey : "";

      chrome.tabs.query({ active: true, currentWindow: true }, (tabs) => {
        if (knownTab) tabs = [knownTab];
        if (!tabs.length) {
          if (requestId) this.ResponseErrorMsg(null, requestId);
          return;
        }
        requestId = requestId || this.beginSummary(tabs[0].id);
        chrome.tabs.sendMessage(tabs[0].id, { message: "ping" }, (response) => {
          if (chrome.runtime.lastError) {
            this.ResponseErrorMsg(response, requestId);
            return;
          }
        });

        const isYouTube = tabs[0].url && tabs[0].url.toLowerCase().includes("youtube");

        if (isYouTube) {
          chrome.tabs.sendMessage(tabs[0].id, { action: "expandYouTubeDescription" }, () => {
            // Wait for expansion before scraping
            setTimeout(() => {
              this.getContentAndSummarize(tabs[0].id, apiKey, tabs[0].url, requestId);
            }, 500);
          });
        } else {
          this.getContentAndSummarize(tabs[0].id, apiKey, tabs[0].url, requestId);
        }
      });
    });
  }

  getContentAndSummarize(tabId, apiKey, url, requestId) {
    requestId = requestId || this.beginSummary(tabId);
    chrome.tabs.sendMessage(tabId, { action: "getContent" }, (response) => {
      if (response && response.content) {
        const divisor = this.isPredominantlyLatinChars(response.content) ? 3000 : 1500;
        this.getStore().dispatch({
          type: "SUMMARY_ESTIMATE",
          requestId,
          estimateSeconds: Math.ceil(response.content.length / divisor),
        });

        this.summarizeContent(response.content, apiKey, url, requestId);
      } else {
        this.ResponseErrorMsg(response, requestId);
      }
    });
  }

  isPredominantlyLatinChars(text) {
    const latinChars = text.match(/[a-zA-Z\u00C0-\u00FF]/g)?.length || 0;
    const squareChars = text.match(/[\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af]/g)?.length || 0;

    return latinChars > squareChars;
  }

  summarizeContent(content, apiKey, url, requestId) {
    responseField.value = "";

    chrome.runtime.sendMessage(
      { action: "summarizeApi", text: content, apiKey: apiKey, url: url },
      (response) => {
        // Treat early close as error
        if (!response || response.error) {
          responseField.value = `API Error: ${response?.error || "No response from background"}`;
          this.ResponseErrorMsg(response, requestId);
        } else {
          responseField.value = response;
          try {
            this.createSummaryList(response, requestId);
          } catch (error) {
            responseField.value = `HTML Error: ${error}`;
            this.ResponseErrorMsg(response, requestId);
          }
        }
      }
    );
  }

  createSummaryList(response, requestId = null) {
    const summaryItems = this.parseSummaryItems(response);
    if (summaryItems.length === 0) {
      throw new Error("No summary items found in response");
    }

    const timestamp = Date.now();
    this.getStore().dispatch({
      type: "SUMMARY_SUCCESS",
      requestId,
      items: summaryItems,
      timestamp,
    });
    // Don't persist summaries in incognito mode
    chrome.storage.local.get("isIncognito", ({ isIncognito = false }) => {
      if (!isIncognito) {
        chrome.storage.local.set({
          summaryList: summaryItems,
          timestamp,
        });
      }
    });
  }

  RecordSummaryTab() {
    chrome.tabs.query({ active: true, currentWindow: true }, (tabs) => {
      this.getStore().summarizedTabId = tabs[0]?.id;
    });
  }

  ResponseErrorMsg(response, requestId = null) {
    const errorMsg = response?.error || "";
    this.getStore().dispatch({
      type: "SUMMARY_ERROR",
      requestId,
      errorKey: errorMsg.includes("overloaded") ? "geminiOverloadMsg" : "geminiErrorMsg",
    });
  }

  render(snapshot, meta = {}) {
    const statusMessage = document.getElementById("geminiEmptyMessage");
    const listContainer = document.getElementById("summaryList");
    const clearAction = document.getElementById("clearButtonSummary");
    const apiAction = document.getElementById("apiButton");
    const sendAction = document.getElementById("sendButton");
    const videoAction = document.getElementById("videoSummaryButton");
    const undoAction = document.getElementById("undoButtonSummary");
    if (
      !statusMessage ||
      !listContainer ||
      !clearAction ||
      !apiAction ||
      !sendAction ||
      !undoAction
    )
      return;
    const { summary, api, favorite: favoriteState } = snapshot;
    const ready = summary.phase === "ready" && summary.items.length > 0;
    const generating = summary.phase === "generating";
    // Starting a new generate consumes the undo window: SUMMARY_STORAGE_SET is a
    // no-op while generating, so a still-visible Undo button would just be a dead click.
    const undoing = Boolean(this._undoWindow.pending) && !ready && !generating;
    let messageKey = "geminiEmptyMsg";
    let substitutions;

    if (generating) {
      if (Number.isFinite(summary.estimateSeconds)) {
        messageKey = "geminiLoadMsg";
        substitutions = String(summary.estimateSeconds);
      } else {
        messageKey = "geminiLoadMsgNoEstimate";
      }
    } else if (summary.phase === "error") {
      messageKey = summary.errorKey || "geminiErrorMsg";
    } else if (api.status === "invalid") {
      messageKey = "apiInvalidMsg";
    } else if (api.status === "missing") {
      messageKey = "geminiFirstMsg";
    }

    statusMessage.style.whiteSpace = "pre-line";
    const message = chrome.i18n.getMessage(messageKey, substitutions);
    statusMessage.textContent = message;
    statusMessage.innerText = message;
    statusMessage.classList.toggle("d-none", ready);
    statusMessage.classList.toggle("shineText", generating);

    // Patch favorite icon classNames in place
    const summaryChanged = meta.summaryChanged !== false;
    if (!ready) {
      listContainer.replaceChildren();
    } else if (summaryChanged || listContainer.children.length === 0) {
      listContainer.replaceChildren(this.buildSummaryListElement(summary.items));
    }

    if (ready) {
      const trimmedFavorite = favoriteState.items.map((item) => item.split(" @")[0]);
      const favoriteComponent = this.favoriteComponent || favorite;
      listContainer.querySelectorAll(".summary-list").forEach((item) => {
        const icon = item.querySelector("i");
        if (icon.classList.contains("spring-animation") || icon.classList.contains("unfavoriting"))
          return;
        const itemName = item.querySelector("span:first-child").textContent;
        const newIcon = favoriteComponent.createFavoriteIcon(itemName, trimmedFavorite);
        if (icon.className !== newIcon.className) icon.className = newIcon.className;
        icon.title = newIcon.title;
      });
    }

    clearAction.classList.toggle("d-none", !ready);
    clearAction.disabled = !ready || generating;
    apiAction.classList.toggle("d-none", ready || undoing);
    undoAction.classList.toggle("d-none", !undoing);
    sendAction.disabled = api.status !== "valid" || generating;
    if (videoAction) {
      videoAction.classList.toggle("d-none", !snapshot.video.available);
      videoAction.classList.toggle("active-button", snapshot.video.enabled);
    }
  }
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = Gemini;
}

// ---- components/modal.js ----
class Modal {
  constructor(encryptApiKeyFn = null) {
    this.encryptApiKey = encryptApiKeyFn;
  }

  async loadCrypto() {
    if (!this.encryptApiKey) {
      const { encryptApiKey } = await import(chrome.runtime.getURL("dist/utils/crypto.js"));
      this.encryptApiKey = encryptApiKey;
    }
  }

  async addModalListener() {
    await this.loadCrypto();

    this._setupShortcutsLinks();
    this._setupShortcutsDisplay();
    this._setupApiForm();
    this._setupSettingsScrollFade();
    this._setupOptionalModalLifecycle();
    this._setupDirForm();
    this._setupAuthUserForm();
    this._setupHistoryMaxStepper();

    this._setupInputButtonToggle(authUserInput);
    this._setupInputButtonToggle(dirInput);

    this._setupIncognitoToggle();
    this._setupDarkModeToggle();
    this._setupLanguageDropdown();
    this._setupPremiumPanel();
  }

  // Private setup helpers
  _setupShortcutsLinks() {
    for (let i = 0; i < configureElements.length; i++) {
      configureElements[i].onclick = function (event) {
        if (window.Analytics)
          window.Analytics.trackFeatureClick("configure_shortcuts", "configureLink");
        let userAgent = navigator.userAgent;

        if (/Chrome/i.test(userAgent)) {
          chrome.tabs.create({ url: "chrome://extensions/shortcuts" });
        } else if (/Opera|OPR\//i.test(userAgent)) {
          chrome.tabs.create({ url: "opera://extensions/shortcuts" });
        }

        event.preventDefault();
      };
    }
  }

  // Suggested keys can silently fail if taken by the OS or another extension.
  _setupShortcutsDisplay() {
    if (chrome.runtime && typeof chrome.runtime.getPlatformInfo === "function") {
      chrome.runtime.getPlatformInfo((info) => {
        this._isMac = info?.os === "mac";
        this._updateShortcutsDisplay();
      });
    } else {
      this._updateShortcutsDisplay();
    }

    // The user may (re)assign shortcuts in chrome://extensions/shortcuts without reloading the popup
    const tipsModal = document.getElementById("tipsModal");
    if (tipsModal) {
      tipsModal.addEventListener("show.bs.modal", () => {
        this._updateShortcutsDisplay();
      });
    }
  }

  // "Alt+R / ⌥+R" -> "Alt+R" on Windows/Linux, "⌥+R" on Mac
  _defaultShortcutForPlatform(defaultText) {
    const [primary, mac] = defaultText.split(" / ");
    return this._isMac && mac ? mac : primary;
  }

  _updateShortcutsDisplay() {
    if (!chrome.commands || typeof chrome.commands.getAll !== "function") return;

    chrome.commands.getAll((commands) => {
      commands.forEach((command) => {
        const el = document.querySelector(`#tipsModal p[data-command="${command.name}"]`);
        if (!el) return;

        // Cache the original default text so re-renders don't stack "(Not Set)" onto it
        if (el.dataset.defaultShortcut === undefined) {
          el.dataset.defaultShortcut = el.textContent.trim();
        }

        if (command.shortcut) {
          el.textContent = command.shortcut;
        } else {
          const defaultText = this._defaultShortcutForPlatform(el.dataset.defaultShortcut);
          el.textContent = `${defaultText} (${chrome.i18n.getMessage("shortcutUnsetLabel")})`;
        }
      });
    });
  }

  _setupApiForm() {
    document.getElementById("apiForm").addEventListener("submit", async (event) => {
      event.preventDefault();
      if (window.Analytics) window.Analytics.trackFeatureClick("save_api_key", "apiForm");
      const apiKey = apiInput.value.trim();

      const encrypted = apiKey ? await this.encryptApiKey(apiKey) : "";
      chrome.storage.local.set({ geminiApiKey: encrypted });

      // Wired by popup.js in production
      this.onApiKeyChange(apiKey);
    });

    this.text2Link("apiNote", "Google AI Studio", "https://aistudio.google.com/app/apikey");

    const apiModal = document.getElementById("apiModal");

    apiModal.addEventListener("shown.bs.modal", () => {
      this._updateApiResetButtonVisibility();
    });

    apiModal.addEventListener("hidden.bs.modal", () => {
      apiInput.value = "";
      this._hideInputButtons(apiInput);
    });

    this._setupInputButtonToggle(apiInput);

    this._setupResetButton(apiInput, "geminiApiKey", () => {
      apiInput.placeholder = chrome.i18n.getMessage("apiPlaceholder");
      this.onApiKeyChange("");
    });
  }

  _setupSettingsScrollFade() {
    const optionalModal = document.getElementById("optionalModal");
    const settingsBody = optionalModal.querySelector(".settings-body");
    const settingsModalContent = optionalModal.querySelector(".modal-content");

    const updateFade = () => {
      const atBottom =
        settingsBody.scrollHeight - settingsBody.scrollTop <= settingsBody.clientHeight + 2;
      settingsModalContent.classList.toggle("at-bottom", atBottom);
    };

    optionalModal.addEventListener("shown.bs.modal", () => {
      this._updateResetButtonsVisibility();
      settingsModalContent.classList.remove("at-bottom");
      updateFade();
      settingsBody.addEventListener("scroll", updateFade);
    });

    optionalModal.addEventListener("hide.bs.modal", () => {
      settingsBody.removeEventListener("scroll", updateFade);
    });
  }

  _setupOptionalModalLifecycle() {
    const optionalModal = document.getElementById("optionalModal");
    optionalModal.addEventListener("hidden.bs.modal", () => {
      dirInput.value = "";
      authUserInput.value = "";
      this._hideInputButtons(dirInput);
      this._hideInputButtons(authUserInput);

      this._saveHistoryMax();
    });
  }

  _setupDirForm() {
    document.getElementById("dirForm").addEventListener("submit", (event) => {
      event.preventDefault();
      if (window.Analytics) window.Analytics.trackFeatureClick("save_start_address", "dirForm");

      const startAddr = dirInput.value.trim();

      if (startAddr === "") {
        chrome.storage.local.remove("startAddr");
        dirInput.placeholder = chrome.i18n.getMessage("dirPlaceholder");
      } else {
        chrome.storage.local.set({ startAddr: startAddr });
        dirInput.placeholder = startAddr;
      }
    });

    this._setupResetButton(dirInput, "startAddr", () => {
      dirInput.placeholder = chrome.i18n.getMessage("dirPlaceholder");
    });
  }

  _setupAuthUserForm() {
    document.getElementById("authUserForm").addEventListener("submit", (event) => {
      event.preventDefault();
      if (window.Analytics) window.Analytics.trackFeatureClick("save_auth_user", "authUserForm");

      const authUser = parseInt(authUserInput.value.trim(), 10);

      if (authUserInput.value.trim() === "" || authUser === 0 || isNaN(authUser)) {
        chrome.storage.local.set({ authUser: 0 });
        authUserInput.placeholder = chrome.i18n.getMessage("authUserPlaceholder");
      } else if (authUser > 0) {
        chrome.storage.local.set({ authUser: authUser });
        authUserInput.placeholder = `authuser=${authUser}`;
      }
    });

    this._setupResetButton(
      authUserInput,
      "authUser",
      () => {
        authUserInput.placeholder = chrome.i18n.getMessage("authUserPlaceholder");
      },
      true
    );
  }

  _setupHistoryMaxStepper() {
    const historyMaxDecrement = document.getElementById("historyMaxDecrement");
    const historyMaxIncrement = document.getElementById("historyMaxIncrement");

    historyMaxDecrement.addEventListener("click", () => {
      const currentValue = parseInt(historyMaxInput.value || historyMaxInput.placeholder, 10) || 10;
      const clampedValue = Math.min(100, Math.max(1, currentValue));
      const newValue = Math.max(1, clampedValue - 1);
      historyMaxInput.value = newValue;
    });

    historyMaxIncrement.addEventListener("click", () => {
      const currentValue = parseInt(historyMaxInput.value || historyMaxInput.placeholder, 10) || 10;
      const clampedValue = Math.min(100, Math.max(1, currentValue));
      const newValue = Math.min(100, clampedValue + 1);
      historyMaxInput.value = newValue;
    });
  }

  _setupIncognitoToggle() {
    this._setupToggle(incognitoToggle, "isIncognito", (newState) => {
      if (window.Analytics)
        window.Analytics.trackFeatureClick("incognito_toggle", "incognitoToggle");
      this.updateIncognitoModal(newState);
    });
  }

  _setupDarkModeToggle() {
    this._setupToggle(darkModeToggle, "isDarkMode", (newState) => {
      if (window.Analytics)
        window.Analytics.trackFeatureClick("dark_mode_toggle", "darkModeToggle");
      applyTheme(newState);
    });
  }

  // Language selector uses Bootstrap dropdown; we sync state and persist selection
  _setupLanguageDropdown() {
    const languageDropdown = document.getElementById("languageDropdown");
    if (!languageDropdown || typeof window === "undefined" || !window.I18nUtils) return;

    const toggleBtn = languageDropdown.querySelector(".language-dropdown-toggle");
    const labelEl = languageDropdown.querySelector(".language-dropdown-label");
    const items = languageDropdown.querySelectorAll(".language-dropdown-item");

    const syncDropdownState = (lang, isDirty = false) => {
      // Gray placeholder until user change
      toggleBtn.classList.toggle("is-default", !isDirty);
      items.forEach((item) => {
        const isActive = item.dataset.value === lang;
        item.classList.toggle("active", isActive);
        if (isActive && labelEl) {
          // Prefer i18n message over [data-locale] pass
          const localeKey = item.dataset.locale;
          const localized = localeKey ? chrome.i18n.getMessage(localeKey) : "";
          labelEl.textContent = localized || item.textContent;
        }
      });
    };

    syncDropdownState(window.I18nUtils.getCurrentLanguage());

    const optionalModal = document.getElementById("optionalModal");
    if (optionalModal) {
      optionalModal.addEventListener("show.bs.modal", () => {
        syncDropdownState(window.I18nUtils.getCurrentLanguage(), false);
      });
    }

    items.forEach((item) => {
      item.addEventListener("click", async () => {
        const newLang = item.dataset.value;
        if (newLang === window.I18nUtils.getCurrentLanguage()) return;
        if (window.Analytics)
          window.Analytics.trackFeatureClick("change_language_" + newLang, "languageDropdown");
        // setLanguage applies override synchronously
        await window.I18nUtils.setLanguage(newLang);
        if (typeof window.applyI18n === "function") window.applyI18n();
        syncDropdownState(window.I18nUtils.getCurrentLanguage(), true);
        window.dispatchEvent(new CustomEvent("i18n:changed", { detail: { lang: newLang } }));
      });
    });
  }

  _setupPremiumPanel() {
    paymentButton.addEventListener("click", () => {
      if (window.Analytics) window.Analytics.trackFeatureClick("payment", "paymentButton");
      chrome.runtime.sendMessage({ action: "extPay" });
    });

    restoreButton.addEventListener("click", () => {
      if (window.Analytics) window.Analytics.trackFeatureClick("restore_payment", "restoreButton");
      chrome.runtime.sendMessage({ action: "restorePay" });
    });

    closeButton.addEventListener("click", () => {
      payment.checkPay();
    });
  }

  _replaceTextWithElement(dataLocale, linkText, replacement) {
    const pElement = document.querySelector(`p[data-locale="${dataLocale}"]`);
    if (pElement) {
      pElement.innerHTML = pElement.innerHTML.replace(linkText, replacement);
    }
  }

  text2Link(dataLocale, linkText, linkHref) {
    this._replaceTextWithElement(
      dataLocale,
      linkText,
      `<a href="${linkHref}" target="_blank">${linkText}</a>`
    );
  }

  text2Modal(dataLocale, linkText, modalId) {
    this._replaceTextWithElement(
      dataLocale,
      linkText,
      `<a href="#" data-bs-toggle="modal" data-bs-target="#${modalId}">${linkText}</a>`
    );
  }

  updateOptionalModal(startAddr, authUser, historyMax) {
    dirInput.placeholder = startAddr || chrome.i18n.getMessage("dirPlaceholder");
    authUserInput.placeholder = authUser
      ? `authuser=${authUser}`
      : chrome.i18n.getMessage("authUserPlaceholder");
    historyMaxInput.placeholder = historyMax && historyMax > 0 ? String(historyMax) : "10";
    historyMaxInput.value = "";
  }

  _saveHistoryMax() {
    const inputValue = historyMaxInput.value || historyMaxInput.placeholder;
    const historyMax = parseInt(inputValue, 10);

    if (isNaN(historyMax) || historyMax <= 0) {
      chrome.storage.local.set({ historyMax: 10 });
      historyMaxInput.placeholder = "10";
    } else {
      const clampedValue = Math.min(Math.max(historyMax, 1), 100);
      chrome.storage.local.set({ historyMax: clampedValue });
      historyMaxInput.placeholder = String(clampedValue);
      if (window.Analytics)
        window.Analytics.trackFeatureClick("save_history_max", "historyMaxStepper");
    }
    historyMaxInput.value = "";
  }

  updateToggleUI(isActive, textSelector, iconSelector, toggleElement) {
    // Support legacy text/icon toggle
    const textEl = document.querySelector(textSelector);
    const iconEl = document.querySelector(iconSelector);

    if (textEl && iconEl) {
      textEl.classList.toggle("d-none", isActive);
      iconEl.classList.toggle("d-none", !isActive);
    }

    toggleElement.classList.toggle("toggle-active", isActive);
  }

  _hideInputButtons(inputElement) {
    const submitButton = inputElement.parentElement.querySelector("button[type='submit']");
    const resetButton = inputElement.parentElement.querySelector(".btn-reset");
    if (submitButton) submitButton.classList.add("d-none");
    if (resetButton) resetButton.classList.add("d-none");
  }

  _setupToggle(toggleElement, storageKey, onToggle) {
    toggleElement.addEventListener("click", () => {
      chrome.storage.local.get(storageKey, (result) => {
        const currentState = result[storageKey] || false;
        const newState = !currentState;
        chrome.storage.local.set({ [storageKey]: newState }, () => {
          onToggle(newState);
        });
      });
    });
  }

  _setupInputButtonToggle(inputElement) {
    const submitButton = inputElement.parentElement.querySelector("button[type='submit']");
    const resetButton = inputElement.parentElement.querySelector(".btn-reset");
    if (!submitButton) return;

    inputElement.addEventListener("input", () => {
      if (inputElement.value.trim() === "") {
        submitButton.classList.add("d-none");
        if (resetButton) {
          const defaultPlaceholder = inputElement.dataset.defaultPlaceholder;
          const hasCustomValue =
            defaultPlaceholder && inputElement.placeholder !== defaultPlaceholder;
          resetButton.classList.toggle("d-none", !hasCustomValue);
        }
      } else {
        submitButton.classList.remove("d-none");
        if (resetButton) resetButton.classList.add("d-none");
      }
    });
  }

  _setupResetButton(inputElement, storageKey, onReset, isNumeric = false) {
    const resetButton = inputElement.parentElement.querySelector(".btn-reset");
    if (!resetButton) return;

    const defaultPlaceholder =
      chrome.i18n.getMessage(inputElement.id.replace("Input", "Placeholder")) ||
      inputElement.placeholder;
    inputElement.dataset.defaultPlaceholder = defaultPlaceholder;

    resetButton.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();

      if (window.Analytics)
        window.Analytics.trackFeatureClick("reset_" + storageKey, "resetButton");

      if (isNumeric) {
        chrome.storage.local.set({ [storageKey]: 0 });
      } else {
        chrome.storage.local.remove(storageKey);
      }

      inputElement.value = "";
      onReset();

      resetButton.classList.add("d-none");
    });
  }

  _updateResetButtonsVisibility() {
    chrome.storage.local.get(["startAddr", "authUser"], (result) => {
      const dirResetButton = dirInput.parentElement.querySelector(".btn-reset");
      const authResetButton = authUserInput.parentElement.querySelector(".btn-reset");

      if (dirResetButton) {
        const hasCustomDir = result.startAddr && result.startAddr.trim() !== "";
        dirResetButton.classList.toggle("d-none", !hasCustomDir);
      }

      if (authResetButton) {
        const hasCustomAuth = result.authUser && result.authUser > 0;
        authResetButton.classList.toggle("d-none", !hasCustomAuth);
      }
    });
  }

  _updateApiResetButtonVisibility() {
    chrome.storage.local.get(["geminiApiKey"], (result) => {
      const apiResetButton = apiInput.parentElement.querySelector(".btn-reset");

      if (apiResetButton) {
        const hasApiKey = result.geminiApiKey && result.geminiApiKey.trim() !== "";
        apiResetButton.classList.toggle("d-none", !hasApiKey);
      }
    });
  }

  updateIncognitoModal(isIncognito) {
    this.updateToggleUI(isIncognito, ".incognito-text", ".incognito-icon", incognitoToggle);
  }

  updateDarkModeModal(isDarkMode) {
    this.updateToggleUI(isDarkMode, ".darkmode-text", ".darkmode-icon", darkModeToggle);
  }
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = Modal;
}

// ---- components/onboarding.js ----
/**
 * Lightweight 4-step onboarding for first-time users.
 * Steps: Hints, Favorite, API, Premium.
 * Persistence: chrome.storage.local key `onboardingDone`.
 * setup/cleanup hooks manage transient DOM like the demo history item.
 */
const DEMO_ITEM_CLASS = "onboarding-demo-item";

class Onboarding {
  constructor() {
    this.STORAGE_KEY = "onboardingDone";
    this.steps = [
      {
        targetSelector: '.footer-li[data-bs-target="#tipsModal"]',
        titleKey: "onboardingHintsTitle",
        descKey: "onboardingHintsDesc",
        placement: "top",
      },
      {
        targetSelector: `.${DEMO_ITEM_CLASS} .bi`,
        titleKey: "onboardingFavoriteTitle",
        descKey: "onboardingFavoriteDesc",
        placement: "bottom",
        setup: () => this.injectDemoHistoryItem(),
        cleanup: () => this.removeDemoHistoryItem(),
      },
      {
        targetSelector: "#geminiSummaryButton",
        titleKey: "onboardingApiTitle",
        descKey: "onboardingApiDesc",
        placement: "bottom",
      },
      {
        targetSelector: '.footer-li[data-bs-target="#premiumModal"]',
        titleKey: "onboardingPremiumTitle",
        descKey: "onboardingPremiumDesc",
        placement: "top",
      },
    ];
    this.currentStep = 0;
    this.overlay = null;
    this.spotlight = null;
    this.tooltip = null;
  }

  /**
   * Inject a demo history item to show "add to favorite" feature.
   * Clicks are swallowed and routed to next() to prevent persistence.
   */
  injectDemoHistoryItem() {
    this.store.dispatch({ type: "ONBOARDING_DEMO_SET", visible: true });
    // Click handled in history.js since render() discards bound listeners
  }

  removeDemoHistoryItem() {
    this.store.dispatch({ type: "ONBOARDING_DEMO_SET", visible: false });
  }

  maybeStart() {
    if (!chrome?.storage?.local?.get) return;
    chrome.storage.local.get(this.STORAGE_KEY, (result) => {
      if (result && result[this.STORAGE_KEY]) return;
      // Defer to allow popup paint and i18n
      setTimeout(() => this.start(), 250);
    });
  }

  start() {
    if (this.overlay) return;
    this.currentStep = 0;
    this.buildDOM();
    this.render();
  }

  buildDOM() {
    this.overlay = document.createElement("div");
    this.overlay.id = "onboardingOverlay";
    this.overlay.className = "onboarding-overlay";

    this.spotlight = document.createElement("div");
    this.spotlight.className = "onboarding-spotlight";

    this.tooltip = document.createElement("div");
    this.tooltip.className = "onboarding-tooltip";
    this.tooltip.setAttribute("role", "dialog");
    this.tooltip.setAttribute("aria-live", "polite");

    // Build tooltip structure once
    this.tooltip.innerHTML = `
      <div class="onboarding-tooltip-header">
        <span class="onboarding-tooltip-title"></span>
        <span class="onboarding-tooltip-counter"></span>
      </div>
      <p class="onboarding-tooltip-desc"></p>
      <div class="onboarding-tooltip-actions">
        <button type="button" class="btn btn-link btn-sm onboarding-skip"></button>
        <button type="button" class="btn btn-primary btn-sm onboarding-next"></button>
      </div>
    `;
    this._titleEl = this.tooltip.querySelector(".onboarding-tooltip-title");
    this._counterEl = this.tooltip.querySelector(".onboarding-tooltip-counter");
    this._descEl = this.tooltip.querySelector(".onboarding-tooltip-desc");
    this._skipBtn = this.tooltip.querySelector(".onboarding-skip");
    this._nextBtn = this.tooltip.querySelector(".onboarding-next");
    this._skipBtn.addEventListener("click", () => this.finish());
    this._nextBtn.addEventListener("click", () => this.next());

    this.overlay.appendChild(this.spotlight);
    this.overlay.appendChild(this.tooltip);
    document.body.appendChild(this.overlay);
  }

  render() {
    const step = this.steps[this.currentStep];
    if (!step) {
      this.finish();
      return;
    }

    if (step.setup && !step._setupDone) {
      try {
        step.setup();
      } catch (err) {
        console.error("Onboarding step setup failed:", err);
      }
      step._setupDone = true;
    }

    const target = document.querySelector(step.targetSelector);
    if (!target) {
      this.finish();
      return;
    }

    const rect = target.getBoundingClientRect();
    const top = Math.max(rect.top, 4);
    const left = Math.max(rect.left, 4);
    const width = rect.width;
    const height = rect.height;

    Object.assign(this.spotlight.style, {
      top: `${top}px`,
      left: `${left}px`,
      width: `${width}px`,
      height: `${height}px`,
    });

    const title = chrome.i18n.getMessage(step.titleKey) || "";
    const desc = chrome.i18n.getMessage(step.descKey) || "";
    const nextLabel =
      this.currentStep === this.steps.length - 1
        ? chrome.i18n.getMessage("onboardingDoneBtn") || "Got it"
        : chrome.i18n.getMessage("onboardingNextBtn") || "Next";
    const skipLabel = chrome.i18n.getMessage("onboardingSkipBtn") || "Skip";
    const counter = `${this.currentStep + 1} / ${this.steps.length}`;

    this._titleEl.textContent = title;
    this._counterEl.textContent = counter;
    this._descEl.textContent = desc;
    this._skipBtn.textContent = skipLabel;
    this._nextBtn.textContent = nextLabel;

    this.positionTooltip(rect, step.placement);
  }

  positionTooltip(targetRect, placement) {
    this.tooltip.style.visibility = "hidden";
    this.tooltip.style.top = "0px";
    this.tooltip.style.left = "0px";

    const ttRect = this.tooltip.getBoundingClientRect();
    const margin = 12;
    const viewportW = document.documentElement.clientWidth;
    const viewportH = document.documentElement.clientHeight;

    let top;
    if (placement === "top") {
      top = targetRect.top - ttRect.height - margin;
      if (top < 8) top = targetRect.bottom + margin; // Flip if no room
    } else {
      top = targetRect.bottom + margin;
      if (top + ttRect.height > viewportH - 8) top = targetRect.top - ttRect.height - margin;
    }

    let left = targetRect.left + targetRect.width / 2 - ttRect.width / 2;
    left = Math.max(8, Math.min(left, viewportW - ttRect.width - 8));
    top = Math.max(8, Math.min(top, viewportH - ttRect.height - 8));

    this.tooltip.style.top = `${top}px`;
    this.tooltip.style.left = `${left}px`;
    this.tooltip.style.visibility = "visible";
  }

  next() {
    // Clean up leaving step to remove transient DOM
    const leaving = this.steps[this.currentStep];
    if (leaving?.cleanup && leaving._setupDone) {
      try {
        leaving.cleanup();
      } catch (err) {
        console.error("Onboarding step cleanup failed:", err);
      }
      leaving._setupDone = false;
    }

    this.currentStep += 1;
    if (this.currentStep >= this.steps.length) {
      this.finish();
      return;
    }
    this.render();
  }

  finish() {
    // Run pending cleanups
    this.steps.forEach((s) => {
      if (s._setupDone && s.cleanup) {
        try {
          s.cleanup();
        } catch (err) {
          console.error("Onboarding step cleanup failed:", err);
        }
        s._setupDone = false;
      }
    });

    if (chrome?.storage?.local?.set) {
      chrome.storage.local.set({ [this.STORAGE_KEY]: true });
    }
    if (this.overlay && this.overlay.parentNode) {
      this.overlay.parentNode.removeChild(this.overlay);
    }
    this.overlay = null;
    this.spotlight = null;
    this.tooltip = null;
    this._titleEl = null;
    this._counterEl = null;
    this._descEl = null;
    this._skipBtn = null;
    this._nextBtn = null;
  }
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = Onboarding;
}

// ---- utils/payment.js ----
class Payment {
  checkPay() {
    chrome.runtime.sendMessage({ action: "checkPay" }, (response) => {
      if (!response || !response.result) {
        return;
      }

      state.paymentStage = response.result;

      this.updateShortcutDisplay();
      this.updateNoteDisplay();
    });
  }

  updateShortcutDisplay() {
    if (
      state.paymentStage.isTrial ||
      state.paymentStage.isExpiredTrial ||
      state.paymentStage.isPremium
    ) {
      Array.from(shortcutTip).forEach((element) => {
        element.classList.remove("premium-only");
      });
    }
  }

  updateNoteDisplay() {
    if (state.paymentStage.isFirst) {
      premiumNoteElement.innerHTML = chrome.i18n.getMessage("firstNote");
    } else if (state.paymentStage.isExpiredTrial) {
      premiumNoteElement.innerHTML = chrome.i18n.getMessage("expiredNote");
      modal.text2Link("premiumNote", "ExtensionPay", "https://extensionpay.com/");
    } else if (state.paymentStage.isTrial) {
      const trialEndOn = this.calcTrialEndDate(state.paymentStage.trialEnd);
      paymentSpan.innerHTML = chrome.i18n.getMessage("trialNote", trialEndOn);
      premiumNoteElement.innerHTML = chrome.i18n.getMessage("remindNote");
      modal.text2Modal("premiumNote", "Gemini AI", "apiModal");
      modal.text2Modal("premiumNote", "Alt+S / ⌥+S", "tipsModal");
    } else if (state.paymentStage.isPremium) {
      const feedbackUrl = "https://forms.fillout.com/t/dFSEkAwKYKus";
      premiumNoteElement.innerHTML = chrome.i18n.getMessage("premiumNote");
      modal.text2Link("premiumNote", "回饋", feedbackUrl);
      modal.text2Link("premiumNote", "feedback", feedbackUrl);
      modal.text2Link("premiumNote", "フィードバック", feedbackUrl);
    }
  }

  calcTrialEndDate(timestamp) {
    const date = new Date(timestamp);
    const shortDate = date.toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
    });
    const time = date.toLocaleTimeString("en-US", {
      hour: "2-digit",
      minute: "2-digit",
      hour12: false,
    });
    return `${shortDate}, ${time}`;
  }
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = Payment;
}

